import{_ as t,o,c as s,a3 as i}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"17. Dispute Resolution Procedure","description":"","frontmatter":{"title":"17. Dispute Resolution Procedure","eba":"Health Allied & Managers Admin 2021-2025","topics":["leave","parental-leave","disputes","flexible-work"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.md","filePath":"ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.md"}'),r={name:"ebas/has-managers-admin/common-terms/consultation-disputes/17-dispute-resolution-procedure.md"};function n(a,e,p,l,d,h){return o(),s("div",null,[...e[0]||(e[0]=[i('<h1 id="_17-dispute-resolution-procedure" tabindex="-1">17. Dispute Resolution Procedure <a class="header-anchor" href="#_17-dispute-resolution-procedure" aria-label="Permalink to &quot;17. Dispute Resolution Procedure&quot;">​</a></h1><p><strong>17.1</strong> Resolution of disputes and grievances</p><p><strong>(a)</strong> For the purpose of this clause 17, a dispute includes a grievance.</p><p><strong>(b)</strong> This dispute resolution procedure will apply to any dispute arising in relation to:</p><p><strong>(i)</strong> this Agreement;</p><p><strong>(ii)</strong> the NES;</p><p><strong>(iii)</strong> a request for an additional 12 months parental leave; or</p><p><strong>(iv)</strong> a request for flexible working arrangements.</p><p><strong>(c)</strong> A party to the dispute may choose to be represented at any stage by a representative including the HWU or employer organisation. A representative, including the HWU or employer organisation on behalf of an Employer, may initiate a dispute.</p><p><strong>17.2</strong> Obligations</p><p><strong>(a)</strong> The parties to the dispute and their representatives must genuinely attempt to resolve the dispute through the processes set out in this clause and must cooperate to ensure that these processes are carried out expeditiously.</p><p><strong>(b)</strong> While the dispute resolution procedure is being conducted work will continue normally according to the usual practice that existed before the dispute, until the dispute is resolved.</p><p><strong>(c)</strong> This requirement does not apply where an Employee:</p><p><strong>(i)</strong> has a reasonable concern about an imminent risk to his or her health or safety;</p><p><strong>(ii)</strong> has advised the Employer of the concern; and</p><p><strong>(iii)</strong> has not unreasonably failed to comply with a direction by the Employer to perform other available work that is safe and appropriate for the Employee to perform.</p><p><strong>(d)</strong> No party to a dispute or person covered by the Agreement will be prejudiced with respect to the resolution of the dispute by continuing work under this clause.</p><p><strong>17.3</strong> Dispute settlement facilitation</p><p><strong>(a)</strong> Where the chosen representative is another Employee of the Employer, that Employee will be released by the Employer from normal duties as is reasonably necessary to enable them to represent the Employee/s including:</p><p><strong>(i)</strong> investigating the circumstances of the dispute; and</p><p><strong>(ii)</strong> participating in the processes to resolve the dispute, including conciliation and arbitration.</p><p><strong>(b)</strong> An Employee who is part of the dispute will be released by the Employer from normal duties as is reasonably necessary to enable them to participate in this dispute settling procedure so long as it does not unduly affect the operations of the Employer.</p><p><strong>17.4</strong> Discussion of dispute at workplace</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(a)</strong> The parties will attempt to resolve the dispute at the workplace as follows:</p><p><strong>(i)</strong> in the first instance by discussions between the Employee/s and the relevant supervisor; and</p><p><strong>(ii)</strong> if the dispute is still unresolved, by discussions between the Employee/s and more senior levels of local management.</p><p><strong>(b)</strong> The discussions at subclause 17.4(a) will take place within fourteen days or such longer period as mutually agreed save that agreement will not be unreasonably withheld.</p><p><strong>(c)</strong> If a dispute cannot be resolved at the workplace it may be referred by a party to the dispute or representative to the Commission for conciliation and, if the matter in dispute remains unresolved, arbitration.</p><p><strong>17.5</strong> Disputes of a collective character Disputes of a collective character may be dealt with more expeditiously by an early reference to the Commission. However, no dispute of a collective character may be referred to the Commission directly without a genuine attempt to resolve the dispute at the workplace level.</p><p><strong>17.6</strong> Conciliation</p><p><strong>(a)</strong> Where a dispute is referred for conciliation, the Commission member will do everything the member deems right and proper to assist the parties to settle the dispute.</p><p><strong>(b)</strong> Conciliation before the Commission is complete when:</p><p><strong>(i)</strong> the parties to the dispute agree that it is settled; or</p><p><strong>(ii)</strong> the Commission member conducting the conciliation, either on their own motion or after an application by a party, is satisfied there is no likelihood that further conciliation will result in settlement within a reasonable period; or</p><p><strong>(iii)</strong> the parties to the dispute inform the Commission member there is no likelihood the dispute will be settled and the member does not have substantial reason to refuse to regard conciliation as complete.</p><p><strong>17.7</strong> Arbitration</p><p><strong>(a)</strong> If, when conciliation is complete, the dispute is not settled, either party may request the Commission proceed to determine the dispute by arbitration.</p><p><strong>(b)</strong> The Commission member that conciliated the dispute will not arbitrate the dispute if a party objects to the member doing so.</p><p>PART B – CONSULTATION, DISPUTE RESOLUTION AND DISCIPLNE</p><p><strong>(c)</strong> Subject to subclause 17.7(d) below, a decision of the Commission is binding upon the persons covered by this Agreement.</p><p><strong>(d)</strong> An appeal lies to a Full Bench of the Commission, with the leave of the Full Bench, against a determination of a single member of the Commission made pursuant to this clause.</p><p><strong>17.8</strong> Conduct of matters before the Commission Subject to any agreement between the parties to the dispute in relation to a particular dispute or grievance and the provisions of this clause, in dealing with a dispute or grievance through conciliation or arbitration, the Commission will conduct the matter in accordance with sections 577, 578 and Subdivision B of Division 3 of Part 5-1 of the Act.</p><p>Plain language terms: dispute, grievance, FWC dispute.</p>',44)])])}const m=t(r,[["render",n]]);export{c as __pageData,m as default};
